from flask import Flask, request, jsonify
import pandas as pd
import tensorflow as tf
from tensorflow.keras import layers, models
import os

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

model = None

def create_model():
    model = models.Sequential([
        layers.Conv2D(32, (3, 3), activation='relu', input_shape=(150, 150, 3)),
        layers.MaxPooling2D(pool_size=(2, 2)),
        layers.Conv2D(64, (3, 3), activation='relu'),
        layers.MaxPooling2D(pool_size=(2, 2)),
        layers.Conv2D(128, (3, 3), activation='relu'),
        layers.MaxPooling2D(pool_size=(2, 2)),
        layers.Flatten(),
        layers.Dense(128, activation='relu'),
        layers.Dense(10, activation='softmax')  # Adjust output classes as needed
    ])
    model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])
    return model

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and file.filename.endswith('.csv'):
        file_path = os.path.join(UPLOAD_FOLDER, file.filename)
        file.save(file_path)
        train_model(file_path)
        return jsonify({'message': 'File uploaded and model trained'}), 200
    return jsonify({'error': 'Invalid file type'}), 400

def train_model(csv_file):
    global model
    if model is None:
        model = create_model()
    
    data = pd.read_csv(csv_file)
    # Assume the CSV has 'image_path' and 'label' columns
    images = []
    labels = []
    for index, row in data.iterrows():
        img = tf.keras.preprocessing.image.load_img(row['image_path'], target_size=(150, 150))
        img_array = tf.keras.preprocessing.image.img_to_array(img)
        images.append(img_array)
        labels.append(row['label'])
    
    images = tf.convert_to_tensor(images)
    labels = tf.convert_to_tensor(labels)
    
    model.fit(images, labels, epochs=5)  # Adjust epochs as needed

@app.route('/contribute', methods=['POST'])
def contribute_example():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and file.filename.endswith('.csv'):
        file_path = os.path.join(UPLOAD_FOLDER, file.filename)
        file.save(file_path)
        train_model(file_path)
        return jsonify({'message': 'Contribution received and model updated'}), 200
    return jsonify({'error': 'Invalid file type'}), 400

if __name__ == '__main__':
    app.run(debug=False)